CREATE OR REPLACE FUNCTION public.calculate_trending_score(article_id uuid, base_score numeric DEFAULT 50.0)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
DECLARE
    final_score DECIMAL := base_score;
    article_age_hours INTEGER;
    category_boost DECIMAL := 0.0;
    breaking_boost DECIMAL := 0.0;
    hot_boost DECIMAL := 0.0;
    recency_factor DECIMAL := 1.0;
BEGIN
    -- Get article age in hours
    SELECT EXTRACT(EPOCH FROM (NOW() - created_at)) / 3600
    INTO article_age_hours
    FROM digest_articles
    WHERE id = article_id;

    -- Apply recency factor (newer articles get higher scores)
    IF article_age_hours <= 2 THEN
        recency_factor := 2.0;
    ELSIF article_age_hours <= 6 THEN
        recency_factor := 1.5;
    ELSIF article_age_hours <= 12 THEN
        recency_factor := 1.2;
    ELSIF article_age_hours <= 24 THEN
        recency_factor := 1.0;
    ELSE
        recency_factor := 0.8;
    END IF;

    -- Apply category-specific boosts
    SELECT CASE
        WHEN category IN ('Technology', 'Business') THEN 10.0
        WHEN category IN ('Environment', 'Science') THEN 8.0
        WHEN category IN ('Health', 'Politics') THEN 6.0
        ELSE 5.0
    END INTO category_boost
    FROM digest_articles
    WHERE id = article_id;

    -- Apply breaking/hot article boosts
    SELECT
        CASE WHEN is_breaking THEN 20.0 ELSE 0.0 END,
        CASE WHEN is_hot THEN 15.0 ELSE 0.0 END
    INTO breaking_boost, hot_boost
    FROM digest_articles
    WHERE id = article_id;

    -- Calculate final score
    final_score := (base_score + category_boost + breaking_boost + hot_boost) * recency_factor;

    -- Cap the score at 100
    IF final_score > 100.0 THEN
        final_score := 100.0;
    END IF;

    RETURN final_score;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.calculate_user_level(points integer)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
BEGIN
    CASE
        WHEN points >= 5000 THEN RETURN 'Master';
        WHEN points >= 3000 THEN RETURN 'Expert';
        WHEN points >= 1500 THEN RETURN 'Advanced';
        WHEN points >= 500 THEN RETURN 'Intermediate';
        ELSE RETURN 'Beginner';
    END CASE;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cleanup_expired_quiz_sessions()
 RETURNS integer
 LANGUAGE plpgsql
AS $function$
DECLARE
    expired_count INTEGER;
BEGIN
    -- Mark sessions as abandoned if inactive for more than 24 hours
    UPDATE quiz_sessions
    SET session_state = 'abandoned',
        updated_at = CURRENT_TIMESTAMP
    WHERE session_state IN ('active', 'paused')
    AND last_activity_at < CURRENT_TIMESTAMP - INTERVAL '24 hours';

    GET DIAGNOSTICS expired_count = ROW_COUNT;

    -- Also update corresponding quiz attempts
    UPDATE quiz_attempts
    SET status = 'abandoned',
        updated_at = CURRENT_TIMESTAMP
    WHERE id IN (
        SELECT attempt_id FROM quiz_sessions
        WHERE session_state = 'abandoned'
        AND status != 'abandoned'
    );

    RETURN expired_count;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.cleanup_friendship_on_status_change()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- If a friend request is cancelled or deleted, remove the friendship
    IF (OLD.status = 'accepted' AND NEW.status IN ('cancelled', 'rejected')) OR TG_OP = 'DELETE' THEN
        DELETE FROM friendships
        WHERE (user1_id = LEAST(OLD.requester_id, OLD.requested_id)
               AND user2_id = GREATEST(OLD.requester_id, OLD.requested_id));
    END IF;

    IF TG_OP = 'DELETE' THEN
        RETURN OLD;
    END IF;
    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_challenge_notification()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Create notification for new challenge
    IF TG_OP = 'INSERT' THEN
        INSERT INTO friend_notifications (user_id, type, title, message, related_user_id, created_at)
        SELECT
            NEW.challenged_id,
            'challenge_received',
            'New Challenge Received',
            u.name || ' challenged you to a quiz!',
            NEW.challenger_id,
            CURRENT_TIMESTAMP
        FROM users u WHERE u.id = NEW.challenger_id;

        RETURN NEW;
    END IF;

    -- Create notification for challenge status changes
    IF TG_OP = 'UPDATE' THEN
        -- Challenge accepted
        IF NEW.status = 'accepted' AND OLD.status = 'pending' THEN
            INSERT INTO friend_notifications (user_id, type, title, message, related_user_id, created_at)
            SELECT
                NEW.challenger_id,
                'challenge_accepted',
                'Challenge Accepted',
                u.name || ' accepted your challenge!',
                NEW.challenged_id,
                CURRENT_TIMESTAMP
            FROM users u WHERE u.id = NEW.challenged_id;
        END IF;

        -- Challenge declined
        IF NEW.status = 'declined' AND OLD.status = 'pending' THEN
            INSERT INTO friend_notifications (user_id, type, title, message, related_user_id, created_at)
            SELECT
                NEW.challenger_id,
                'challenge_declined',
                'Challenge Declined',
                u.name || ' declined your challenge.',
                NEW.challenged_id,
                CURRENT_TIMESTAMP
            FROM users u WHERE u.id = NEW.challenged_id;
        END IF;

        -- Challenge completed
        IF NEW.status = 'completed' AND OLD.status = 'accepted' THEN
            -- Determine winner and create notifications for both users
            DECLARE
                winner_id UUID;
                winner_name TEXT;
                loser_id UUID;
            BEGIN
                -- Determine winner
                IF NEW.challenger_score > NEW.challenged_score THEN
                    winner_id := NEW.challenger_id;
                    loser_id := NEW.challenged_id;
                ELSIF NEW.challenged_score > NEW.challenger_score THEN
                    winner_id := NEW.challenged_id;
                    loser_id := NEW.challenger_id;
                END IF;

                -- Create completion notification for challenger
                INSERT INTO friend_notifications (user_id, type, title, message, related_user_id, created_at)
                SELECT
                    NEW.challenger_id,
                    'challenge_completed',
                    'Challenge Completed',
                    CASE
                        WHEN NEW.challenger_score > NEW.challenged_score THEN 'You won the challenge against ' || u.name || '!'
                        WHEN NEW.challenger_score < NEW.challenged_score THEN 'You lost the challenge against ' || u.name || '.'
                        ELSE 'Your challenge with ' || u.name || ' ended in a tie!'
                    END,
                    NEW.challenged_id,
                    CURRENT_TIMESTAMP
                FROM users u WHERE u.id = NEW.challenged_id;

                -- Create completion notification for challenged user
                INSERT INTO friend_notifications (user_id, type, title, message, related_user_id, created_at)
                SELECT
                    NEW.challenged_id,
                    'challenge_completed',
                    'Challenge Completed',
                    CASE
                        WHEN NEW.challenged_score > NEW.challenger_score THEN 'You won the challenge against ' || u.name || '!'
                        WHEN NEW.challenged_score < NEW.challenger_score THEN 'You lost the challenge against ' || u.name || '.'
                        ELSE 'Your challenge with ' || u.name || ' ended in a tie!'
                    END,
                    NEW.challenger_id,
                    CURRENT_TIMESTAMP
                FROM users u WHERE u.id = NEW.challenger_id;
            END;
        END IF;

        RETURN NEW;
    END IF;

    RETURN NULL;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.create_friend_request_notification()
 RETURNS trigger
 LANGUAGE plpgsql
