$function$
;

CREATE OR REPLACE FUNCTION public.create_friendship_on_accept()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Only create friendship if status changed to 'accepted'
    IF NEW.status = 'accepted' AND OLD.status != 'accepted' THEN
        -- Ensure user1_id < user2_id for consistent ordering
        INSERT INTO friendships (user1_id, user2_id, created_at, is_test_data)
        VALUES (
            LEAST(NEW.requester_id, NEW.requested_id),
            GREATEST(NEW.requester_id, NEW.requested_id),
            CURRENT_TIMESTAMP,
            true
        )
        ON CONFLICT (user1_id, user2_id) DO NOTHING;

        -- Update responded_at timestamp
        NEW.responded_at = CURRENT_TIMESTAMP;

        -- Create notification for requester
        INSERT INTO friend_notifications (user_id, type, title, message, related_user_id, friend_request_id, created_at, is_test_data)
        SELECT
            NEW.requester_id,
            'friend_accepted',
            'Friend Request Accepted',
            u.name || ' accepted your friend request!',
            NEW.requested_id,
            NEW.id,
            CURRENT_TIMESTAMP,
            true
        FROM users u WHERE u.id = NEW.requested_id;
    END IF;

    -- Create notification for rejection
    IF NEW.status = 'rejected' AND OLD.status != 'rejected' THEN
        NEW.responded_at = CURRENT_TIMESTAMP;

        INSERT INTO friend_notifications (user_id, type, title, message, related_user_id, friend_request_id, created_at, is_test_data)
        SELECT
            NEW.requester_id,
            'friend_rejected',
            'Friend Request Declined',
            u.name || ' declined your friend request.',
            NEW.requested_id,
            NEW.id,
            CURRENT_TIMESTAMP,
            true
        FROM users u WHERE u.id = NEW.requested_id;
    END IF;

    RETURN NEW;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.expire_challenges()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Auto-expire challenges that are past their expiry date
    UPDATE challenges
    SET status = 'expired', updated_at = CURRENT_TIMESTAMP
    WHERE expires_at < CURRENT_TIMESTAMP
    AND status IN ('pending', 'accepted');

    RETURN NULL;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_digest_categories()
 RETURNS TABLE(category character varying)
 LANGUAGE plpgsql
AS $function$
BEGIN
    RETURN QUERY
    SELECT DISTINCT da.category
    FROM digest_articles da
    WHERE da.is_dummy = false
    ORDER BY da.category;
END;
$function$
;

CREATE OR REPLACE FUNCTION public.get_or_create_todays_digest()
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
    digest_id UUID;
BEGIN
    -- Try to find today's digest
    SELECT id INTO digest_id
    FROM digests
    WHERE date = CURRENT_DATE;

    -- If not found, create it
    IF digest_id IS NULL THEN
        INSERT INTO digests (date, title, summary, is_dummy)
        VALUES (
            CURRENT_DATE,
            'Daily News Digest',
            'Stay informed with the most important news from around the world.',
            false
        )
        RETURNING id INTO digest_id;
    END IF;

    RETURN digest_id;
END;
$function$
;

