CREATE OR REPLACE FUNCTION public.update_digest_article_count()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    IF TG_OP = 'INSERT' THEN
        UPDATE digests
        SET article_count = (
            SELECT COUNT(*)
            FROM digest_articles
            WHERE digest_id = NEW.digest_id
        ),
        updated_at = NOW()
        WHERE id = NEW.digest_id;
        RETURN NEW;
    ELSIF TG_OP = 'DELETE' THEN
        UPDATE digests
        SET article_count = (
            SELECT COUNT(*)
            FROM digest_articles
            WHERE digest_id = OLD.digest_id
        ),
        updated_at = NOW()
        WHERE id = OLD.digest_id;
        RETURN OLD;
    END IF;
    RETURN NULL;
END;
$function$
;

