CREATE TRIGGER trigger_update_digest_article_count_insert AFTER INSERT ON public.digest_articles FOR EACH ROW EXECUTE FUNCTION update_digest_article_count();
CREATE TRIGGER trigger_update_digests_updated_at BEFORE UPDATE ON public.digests FOR EACH ROW EXECUTE FUNCTION update_digest_updated_at_column();
